mapper.select:
/*disMgmtMapper.getPrcSocList*/
SELECT SOC
FROM MSP_DIS_ADD
WHERE PRMT_ID = #{prmtId}

mapper.update:
/*disMgmtMapper.updateTrgFnlProc*/
UPDATE MSP_DIS_TRG_FNL
SET PROC_ID = 'BATCH3'
  , PROC_DTTM = SYSDATE

  , PROC_YN='Y'

WHERE TRG_FNL_SEQ = #{trgFnlSeq}

mapper.insert:
 /*disMgmtMapper.insertPrmtAutoAddDtl*/
 INSERT INTO MSP_DIS_PRC_DTL(
     PRC_DTL_SEQ
    ,PRC_MST_SEQ
    ,SEQ
    ,CONTRACT_NUM
    ,NCN
    ,GLOBAL_NO
    ,SOC
    ,RSLT_CD
    ,PRCS_SBST
    ,REGST_ID
    ,REGST_DTTM
 )VALUES(
    #{prcDtlSeq}
    ,#{prcMstSeq}
    ,(SELECT NVL(MAX(SEQ), 0)+1 FROM MSP_DIS_PRC_DTL WHERE PRC_DTL_SEQ = #{prcDtlSeq})
    ,#{contractNum}
    ,#{ncn}
    ,#{globalNo}
    ,#{soc}
    ,#{rsltCd}
    ,#{prcsSbst}
    ,'BATCH3'
    ,SYSDATE
)

 /*disMgmtMapper.insertPrmtAutoAddMst*/
 INSERT INTO MSP_DIS_PRC_MST(
     PRC_MST_SEQ
    ,PRMT_ID
    ,CONTRACT_NUM
    ,EVNT_CD
    ,EFFECTIVE_DATE
    ,EFFECTIVE_DT
    ,SUCC_YN
    ,PRMT_AGNT_CD
    ,REGST_ID
    ,REGST_DTTM
 )VALUES(
     #{prcMstSeq}
    ,#{prmtId}
    ,#{contractNum}
    ,#{evntCd}
    ,#{effectiveDate}
    ,SUBSTR(#{effectiveDate},1,8)
    ,#{succYn}
    ,(SELECT PRMT_AGNT_CD FROM MSP_DIS_TRG_FNL_INF WHERE TRG_FNL_INF_SEQ = #{trgFnlInfSeq})
    ,'BATCH3'
    ,SYSDATE
)
